import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("Corrupted holdings data:", e);
      return [];
    }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("Failed to load vault history");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this strategy permanently?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((item) => item.id !== id));
      toast.success("Strategy removed");
    } catch (err) {
      toast.error("Failed to delete strategy");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      toast.error("Failed to generate PDF");
    }
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  if (loading) return <div style={centerStyle}>Loading vault...</div>;

  return (
    <div style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={20} color="var(--accent)" /> Strategy Vault
        </h2>
        <span style={nodeCount}>{history.length} entries</span>
      </div>

      {history.length === 0 ? (
        <div style={emptyStyle}>No strategies saved yet.</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={11} /> {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={11} /> {item.risk_score ?? '—'}
                  </span>
                </div>
                <h4 style={titleStyle}>{item.goal || 'Unnamed Strategy'}</h4>

                <div style={tickerRow}>
                  {safeParseHoldings(item.holdings).map((ticker, i) => (
                    <span key={i} style={tickerTag}>
                      {ticker}
                    </span>
                  ))}
                </div>
              </div>

              <div style={actionRow}>
                <button
                  onClick={() => setSelectedItem(item)}
                  style={iconBtn}
                  title="View details"
                >
                  <Eye size={18} />
                </button>
                <button
                  onClick={() => handleDownload(item)}
                  style={iconBtn}
                  title="Download PDF"
                >
                  <Download size={18} />
                </button>
                <button
                  onClick={() => handleDelete(item.id)}
                  style={deleteBtn}
                  title="Delete"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedItem && (
        <div style={modalOverlay} onClick={() => setSelectedItem(null)}>
          <div style={modalContent} onClick={(e) => e.stopPropagation()}>
            <div style={modalHeader}>
              <h3 style={modalTitle}>Strategy #{selectedItem.id}</h3>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}>
                <X size={20} />
              </button>
            </div>

            <div style={modalBody}>
              <div style={section}>
                <div style={sectionLabel}>Summary</div>
                <div style={sectionContent}>
                  {selectedItem.summary || 'No summary available.'}
                </div>
              </div>

              <div style={section}>
                <div style={sectionLabel}>Rationale</div>
                <div style={sectionContent}>
                  {selectedItem.rationale || 'No rationale provided.'}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ────────────────────────────────────────────────
   Styles – refined dark / fintech / terminal theme
───────────────────────────────────────────────── */

const containerStyle = {
  padding: '2rem 1.5rem',
  maxWidth: '1100px',
  margin: '0 auto',
  minHeight: '80vh',
};

const headerRow = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '2.2rem',
  paddingBottom: '1.1rem',
  borderBottom: '1px solid var(--border-subtle)',
};

const headerStyle = {
  color: 'var(--text-strong)',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontSize: '1.25rem',
  fontWeight: 600,
  margin: 0,
};

const nodeCount = {
  fontSize: '0.78rem',
  color: 'var(--text-muted)',
  fontFamily: 'ui-monospace, monospace',
};

const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.1rem' };

const cardStyle = {
  display: 'flex',
  padding: '1.4rem 1.6rem',
  background: 'var(--surface-glass)',
  border: '1px solid var(--border-subtle)',
  borderRadius: '14px',
  gap: '1.4rem',
  transition: 'all 0.16s ease',
  ':hover': {
    transform: 'translateY(-2px)',
    boxShadow: '0 12px 28px rgba(0,0,0,0.28)',
    borderColor: 'var(--accent-dim)',
  },
};

const tagRow = { display: 'flex', gap: '0.9rem', marginBottom: '0.7rem' };

const dateTag = {
  fontSize: '0.73rem',
  color: 'var(--text-muted)',
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const riskTag = {
  fontSize: '0.73rem',
  color: 'var(--accent)',
  fontWeight: 600,
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const titleStyle = {
  margin: '0 0 0.9rem',
  color: 'var(--text-strong)',
  fontSize: '1.08rem',
  fontWeight: 600,
  lineHeight: 1.35,
};

const tickerRow = { display: 'flex', flexWrap: 'wrap', gap: '6px' };

const tickerTag = {
  fontSize: '0.71rem',
  padding: '3px 9px',
  background: 'var(--accent-very-dim)',
  border: '1px solid var(--accent-dim)',
  borderRadius: '6px',
  color: 'var(--accent)',
  fontFamily: 'ui-monospace, monospace',
  fontWeight: 500,
};

const actionRow = {
  display: 'flex',
  flexDirection: 'column',
  gap: '0.7rem',
  paddingLeft: '1.3rem',
  borderLeft: '1px solid var(--border-subtle)',
  justifyContent: 'center',
};

const iconBtn = {
